create extension if not exists pgcrypto;
create table if not exists public.players(id uuid primary key default gen_random_uuid(),pi_uid text not null unique,pi_username text not null,level integer not null default 1 check(level between 1 and 999),xp integer not null default 0 check(xp>=0),last_position jsonb not null default '{"x":0,"y":1,"z":0}',last_login_at timestamptz,created_at timestamptz not null default now());
create table if not exists public.shop_items(id uuid primary key default gen_random_uuid(),code text not null unique,name text not null,pi_price numeric(18,7) not null check(pi_price>0),active boolean not null default true);
create table if not exists public.payment_orders(id uuid primary key default gen_random_uuid(),player_id uuid not null references public.players(id) on delete cascade,item_id uuid not null references public.shop_items(id),expected_amount numeric(18,7) not null check(expected_amount>0),pi_payment_id text unique,pi_txid text unique,status text not null default 'created' check(status in('created','approved','completed','cancelled','failed')),completed_at timestamptz,created_at timestamptz not null default now());
create table if not exists public.player_inventory(id uuid primary key default gen_random_uuid(),player_id uuid not null references public.players(id) on delete cascade,item_id uuid not null references public.shop_items(id),order_id uuid unique references public.payment_orders(id),quantity integer not null default 1 check(quantity>0),created_at timestamptz not null default now(),unique(player_id,item_id));
alter table public.players enable row level security;alter table public.shop_items enable row level security;alter table public.payment_orders enable row level security;alter table public.player_inventory enable row level security;
revoke all on public.players,public.payment_orders,public.player_inventory from anon,authenticated;grant select on public.shop_items to anon,authenticated;
drop policy if exists "public active items" on public.shop_items;create policy "public active items" on public.shop_items for select to anon,authenticated using(active=true);
insert into public.shop_items(code,name,pi_price) values('sun_hat','قبعة الشمس',0.01),('trail_pack','حقيبة الرحلة',0.02) on conflict(code) do update set name=excluded.name,pi_price=excluded.pi_price;
create or replace function public.complete_island_order(p_order_id uuid,p_player_id uuid,p_payment_id text,p_txid text) returns void language plpgsql security definer set search_path=public as $$ declare v_item uuid;begin if p_player_id is null then raise exception 'missing player';end if;select item_id into v_item from payment_orders where id=p_order_id and player_id=p_player_id and pi_payment_id=p_payment_id and status='approved' for update;if v_item is null then if exists(select 1 from payment_orders where id=p_order_id and status='completed') then return;end if;raise exception 'invalid order';end if;update payment_orders set status='completed',pi_txid=p_txid,completed_at=now() where id=p_order_id;insert into player_inventory(player_id,item_id,order_id) values(p_player_id,v_item,p_order_id) on conflict(player_id,item_id) do update set quantity=player_inventory.quantity+1;end;$$;
revoke all on function public.complete_island_order(uuid,uuid,text,text) from public,anon,authenticated;grant execute on function public.complete_island_order(uuid,uuid,text,text) to service_role;
